import org.apache.commons.lang3.StringEscapeUtils;

public class SecureXSSDemo {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Escaping user input before outputting it to HTML
        String escapedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Output the escaped input within proper HTML tags
        String output = "<div>" + escapedInput + "</div>";

        System.out.println(output);
    }
}

